namespace Aspire.Dashboard.Components.Dialogs;

public partial class ExemplarsDialog : IDisposable
{
    [Parameter]
    public ExemplarsDialogViewModel Content { get; set; } = default!;

    [Inject]
    public required BrowserTimeProvider TimeProvider { get; init; }

    [Inject]
    public required DashboardDialogService DialogService { get; init; }

    [Inject]
    public required NavigationManager NavigationManager { get; init; }

    [Inject]
    public required TelemetryRepository TelemetryRepository { get; init; }

    public IQueryable<ChartExemplar> MetricView => Content.Exemplars.AsQueryable();

    private readonly CancellationTokenSource _cts = new();

    public async Task OnViewDetailsAsync(ChartExemplar exemplar)
    {
        var available = await TraceLinkHelpers.WaitForSpanToBeAvailableAsync(
            traceId: exemplar.TraceId,
            spanId: exemplar.SpanId,
            getSpan: TelemetryRepository.GetSpan,
            DialogService,
            InvokeAsync,
            Loc,
            _cts.Token).ConfigureAwait(false);

        if (available)
        {
            NavigationManager.NavigateTo(DashboardUrls.TraceDetailUrl(exemplar.TraceId, spanId: exemplar.SpanId));
        }
    }

    private string GetTitle(ChartExemplar exemplar)
    {
        return (exemplar.Span != null)
            ? SpanWaterfallViewModel.GetTitle(exemplar.Span, Content.Resources)
            : $"{Loc[nameof(Resources.Dialogs.ExemplarsDialogTrace)]}: {OtlpHelpers.ToShortenedId(exemplar.TraceId)}";
    }

    private string FormatMetricValue(double? value)
    {
        if (value is null)
        {
            return string.Empty;
        }

        var formattedValue = value.Value.ToString("F3", CultureInfo.CurrentCulture);
        if (!string.IsNullOrEmpty(Content.Instrument.Unit))
        {
            formattedValue += Content.Instrument.Unit.TrimStart('{').TrimEnd('}');
        }

        return formattedValue;
    }

    public void Dispose()
    {
        _cts.Cancel();
        _cts.Dispose();
    }
}

using System.Globalization;
using System.Text.Encodings.Web;
using Fluid;
using Fluid.Values;
using Microsoft.AspNetCore.Html;

namespace OrchardCore.DisplayManagement.Liquid;

public class HtmlContentValue : FluidValue
{
    private readonly IHtmlContent _value;

    public HtmlContentValue(IHtmlContent value)
    {
        _value = value;
    }

    public override FluidValues Type
        => FluidValues.String;

    public override bool Equals(FluidValue other)
    {
        if (other.IsNil())
        {
            return _value == null;
        }

        return _value == other;
    }

    public override ValueTask<FluidValue> GetValueAsync(string name, TemplateContext context)
    {
        return NilValue.Instance;
    }

    public override bool ToBooleanValue()
    {
        return true;
    }

    public override decimal ToNumberValue()
    {
        return 0;
    }

    public override string ToStringValue()
    {
        return _value.ToString();
    }

    public override ValueTask WriteToAsync(TextWriter writer, TextEncoder encoder, CultureInfo cultureInfo)
    {
        _value.WriteTo(writer, (HtmlEncoder)encoder);

        return ValueTask.CompletedTask;
    }

    public override object ToObjectValue()
    {
        return _value;
    }

    public override bool Contains(FluidValue value)
    {
        return false;
    }

    public override IEnumerable<FluidValue> Enumerate(TemplateContext context)
    {
        return [];
    }

    public override bool Equals(object other)
    {
        // The is operator will return false if null
        if (other is HtmlContentValue otherValue)
        {
            return _value.Equals(otherValue._value);
        }

        return false;
    }

    public override int GetHashCode()
    {
        return _value.GetHashCode();
    }

    [Obsolete("WriteTo is obsolete, prefer the WriteToAsync method.")]
    public override void WriteTo(TextWriter writer, TextEncoder encoder, CultureInfo cultureInfo)
    {
        _value.WriteTo(writer, (HtmlEncoder)encoder);
    }
}

namespace eShop.Ordering.Domain.Seedwork;

public abstract class Entity
{
    int? _requestedHashCode;
    int _Id;
    public virtual int Id
    {
        get
        {
            return _Id;
        }
        protected set
        {
            _Id = value;
        }
    }

    private List<INotification> _domainEvents;
    public IReadOnlyCollection<INotification> DomainEvents => _domainEvents?.AsReadOnly();

    public void AddDomainEvent(INotification eventItem)
    {
        _domainEvents = _domainEvents ?? new List<INotification>();
        _domainEvents.Add(eventItem);
    }

    public void RemoveDomainEvent(INotification eventItem)
    {
        _domainEvents?.Remove(eventItem);
    }

    public void ClearDomainEvents()
    {
        _domainEvents?.Clear();
    }

    public bool IsTransient()
    {
        return this.Id == default;
    }

    public override bool Equals(object obj)
    {
        if (obj == null || !(obj is Entity))
            return false;

        if (Object.ReferenceEquals(this, obj))
            return true;

        if (this.GetType() != obj.GetType())
            return false;

        Entity item = (Entity)obj;

        if (item.IsTransient() || this.IsTransient())
            return false;
        else
            return item.Id == this.Id;
    }

    public override int GetHashCode()
    {
        if (!IsTransient())
        {
            if (!_requestedHashCode.HasValue)
                _requestedHashCode = this.Id.GetHashCode() ^ 31; // XOR for random distribution (http://blogs.msdn.com/b/ericlippert/archive/2011/02/28/guidelines-and-rules-for-gethashcode.aspx)

            return _requestedHashCode.Value;
        }
        else
            return base.GetHashCode();

    }
    public static bool operator ==(Entity left, Entity right)
    {
        if (Object.Equals(left, null))
            return (Object.Equals(right, null)) ? true : false;
        else
            return left.Equals(right);
    }

    public static bool operator !=(Entity left, Entity right)
    {
        return !(left == right);
    }
}

using Microsoft.AspNetCore.Razor.Language;

namespace OrchardCore.DisplayManagement.Liquid.TagHelpers;

public class LiquidTagHelperMatching
{
    private const string AspPrefix = "asp-";
    public static readonly LiquidTagHelperMatching None = new();
    public readonly TagMatchingRuleDescriptor[] _rules = [];

    public LiquidTagHelperMatching()
    {
    }

    public LiquidTagHelperMatching(string name, string assemblyName, IEnumerable<TagMatchingRuleDescriptor> tagMatchingRules)
    {
        Name = name;
        AssemblyName = assemblyName;
        _rules = tagMatchingRules.ToArray();
    }

    public string Name { get; } = string.Empty;
    public string AssemblyName { get; } = string.Empty;

    private static bool Predicate(TagMatchingRuleDescriptor rule, string helper, IEnumerable<string> arguments)
    {
        // Does it match the required tag name
        if (rule.TagName != "*" && !string.Equals(rule.TagName, helper, StringComparison.OrdinalIgnoreCase))
        {
            return false;
        }

        // Does it expect any specific attribute?
        if (!rule.Attributes.Any())
        {
            return true;
        }

        // Are all required attributes present?
        var allRequired = rule.Attributes.All(attr => arguments.Any(name =>
        {
            // Exact match
            if (string.Equals(name, attr.Name, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            // Check by replacing all '_' with '-', e.g. asp_src will map to asp-src
            name = name.Replace('_', '-');

            if (string.Equals(name, attr.Name, StringComparison.OrdinalIgnoreCase))
            {
                return true;
            }

            if (attr.Name.StartsWith(AspPrefix, StringComparison.Ordinal))
            {
                if (name.AsSpan().Equals(attr.Name.AsSpan(AspPrefix.Length), StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }
            }

            return false;
        }));

        if (allRequired)
        {
            return true;
        }

        return false;
    }

    public bool Match(string helper, IEnumerable<string> arguments)
    {
        foreach (var rule in _rules)
        {
            if (Predicate(rule, helper, arguments))
            {
                return true;
            }
        }

        return false;
    }
}

